-- seed row 1
with existing_user as (
  select id
  from auth.users
  where email = 'shaheenvivji@gmail.com' and is_sso_user = false
  limit 1
), inserted_user as (
  insert into auth.users (
    id, instance_id, aud, role, email, email_confirmed_at, created_at, updated_at,
    raw_app_meta_data, raw_user_meta_data, is_sso_user, is_anonymous, phone, phone_confirmed_at
  )
  select
    '6c289c7c-b899-4f08-b903-ae3fb931d94d', gen_random_uuid(), 'authenticated', 'authenticated', 'shaheenvivji@gmail.com', now(), now(), now(),
    '{}'::jsonb, '{}'::jsonb, false, false, NULL, NULL
  where not exists (select 1 from existing_user)
  returning id
), updated_user as (
  update auth.users
  set updated_at = now()
  where id = (select id from existing_user)
  returning id
), user_row as (
  select id from inserted_user
  union all
  select id from updated_user
  union all
  select id from existing_user
  limit 1
), person_existing as (
  select id
  from public.person
  where user_id = (select id from user_row)
  limit 1
), inserted_person as (
  insert into public.person (
    id, user_id, role, email, firstname, surname, phone, postcode, partner_program
  )
  select
    '41bfe553-4788-47bb-b0c1-460401bcf74e', (select id from user_row), 'parent', 'shaheenvivji@gmail.com', 'Shaheen', 'Family', '6477393938',
    NULL, 'Thorncliffe Park -TNO'
  where not exists (select 1 from person_existing)
  returning id
), updated_person as (
  update public.person
  set
    firstname = 'Shaheen',
    surname = 'Family',
    phone = COALESCE('6477393938', phone),
    postcode = NULL,
    partner_program = 'Thorncliffe Park -TNO'
  where id = (select id from person_existing)
  returning id
), person_row as (
  select id from inserted_person
  union all
  select id from updated_person
  union all
  select id from person_existing
  limit 1
), submission_row as (
  insert into public.form_submission (id, form_id, user_id, submitted_at)
  select gen_random_uuid(), f.id, (select id from user_row), now()
  from public.form f
  where f.name = 'Onboarding Survey'
  on conflict (form_id, user_id) do update set submitted_at = now()
  returning id
)
insert into public.form_answer (submission_id, question_code, value)
select submission_row.id, 'onboarding_where_you_live', to_jsonb(''::text)
from submission_row
union all
select submission_row.id, 'onboarding_prior_participation', to_jsonb('yes'::text)
from submission_row
union all
select submission_row.id, 'onboarding_partner_program', to_jsonb('Thorncliffe Park -TNO'::text)
from submission_row
on conflict (submission_id, question_code) do update set value = excluded.value;


